  1194→          : '';
  1195→
  1196→        get().logActivity(taskId, {
  1197→          action: 'created',
  1198→          field: 'dependency',
  1199→          newValue: `Depends on task ${dependency.taskId} (${dependencyLabel}${lagLabel})`,
  1200→        });
  1201→      },
  1202→
  1203→      removeDependency: (taskId, dependencyId) => {
  1204→        const task = get().tasks.find(t => t.id === taskId);
  1205→        if (!task || !task.dependencies) {
  1206→          log.warn('Task or dependencies not found', { taskId });
  1207→          return;
  1208→        }
  1209→
  1210→        const dependency = task.dependencies.find(d => d.taskId === dependencyId);
  1211→        if (!dependency) {
  1212→          log.warn('Dependency not found', { taskId, dependencyId });
  1213→          return;
  1214→        }
  1215→
  1216→        // Remove dependency from task
  1217→        set((state) => ({
  1218→          tasks: state.tasks.map(t => {
  1219→            if (t.id === taskId) {
  1220→              return {
  1221→                ...t,
  1222→                dependencies: (t.dependencies || []).filter(d => d.taskId !== dependencyId),
  1223→              };
  1224→            }
  1225→            return t;
  1226→          }),
  1227→        }));
  1228→
  1229→        // Log activity
  1230→        const dependencyLabel = {
  1231→          'finish-to-start': 'FS',
  1232→          'start-to-start': 'SS',
  1233→          'finish-to-finish': 'FF',
  1234→          'start-to-finish': 'SF',
  1235→        }[dependency.type];
  1236→
  1237→        get().logActivity(taskId, {
  1238→          action: 'updated',
  1239→          field: 'dependency',
  1240→          oldValue: `Depended on task ${dependencyId} (${dependencyLabel})`,
  1241→        });
  1242→      },
  1243→
  1244→      getBlockers: (taskId) => {
  1245→        // Get tasks that this task depends on (blockers)
  1246→        const task = get().tasks.find(t => t.id === taskId);
  1247→        if (!task || !task.dependencies) return [];
  1248→
  1249→        const blockerIds = task.dependencies.map(d => d.taskId);
  1250→        return get().tasks.filter(t => blockerIds.includes(t.id));
  1251→      },
  1252→
  1253→      getBlocked: (taskId) => {
  1254→        // Get tasks that depend on this task (blocked by this task)
  1255→        const allTasks = get().tasks;
  1256→        return allTasks.filter(t =>
  1257→          t.dependencies?.some(d => d.taskId === taskId)
  1258→        );
  1259→      },
  1260→
  1261→      getOverdueBlockers: (taskId) => {
  1262→        // P1: Get blocker tasks that are overdue (for dependency warnings)
  1263→        const blockers = get().getBlockers(taskId);
  1264→        const today = new Date();
  1265→        today.setHours(0, 0, 0, 0); // Start of day
  1266→
  1267→        return blockers.filter(blocker => {
  1268→          // Blocker is overdue if:
  1269→          // 1. It's not done
  1270→          // 2. It has a due date
  1271→          // 3. Due date is before today
  1272→          if (blocker.status === 'done') return false;
  1273→          if (!blocker.dueDate) return false;
  1274→
  1275→          const dueDate = new Date(blocker.dueDate);
  1276→          dueDate.setHours(0, 0, 0, 0);
  1277→
  1278→          return dueDate < today;
  1279→        });
  1280→      },
  1281→
  1282→      // ==================== PHASE 1.2: AUTO-SHIFT DEPENDENT TASKS ====================
  1283→
  1284→      applyDependentShifts: (shifts) => {
  1285→        if (shifts.length === 0) return;
  1286→
  1287→        log.info(`Applying ${shifts.length} dependent task shifts`);
  1288→
  1289→        set((state) => ({
  1290→          tasks: state.tasks.map((task) => {
  1291→            const shift = shifts.find(s => s.taskId === task.id);
  1292→            if (!shift) return task;
  1293→
  1294→            return {
  1295→              ...task,
  1296→              startDate: shift.newStartDate,
  1297→              dueDate: shift.newDueDate,
  1298→            };
  1299→          }),
  1300→        }));
  1301→
  1302→        // Log activity for each shifted task
  1303→        shifts.forEach(shift => {
  1304→          get().logActivity(shift.taskId, {
  1305→            action: 'updated',
  1306→            field: 'dates',
  1307→            newValue: shift.reason,
  1308→          });
  1309→        });
  1310→
  1311→        log.info('Dependent shifts applied successfully');
  1312→      },
  1313→
  1314→      // ==================== PHASE 1.3: CRITICAL PATH ANALYSIS ====================
  1315→
  1316→      getCriticalPath: () => {
  1317→        const tasks = get().tasks;
  1318→        return calculateCriticalPath(tasks);
  1319→      },
  1320→
  1321→      getTaskSlack: (taskId) => {
  1322→        const tasks = get().tasks;
  1323→        const task = tasks.find(t => t.id === taskId);
  1324→        if (!task) return 0;
  1325→        return calculateSlack(task, tasks);
  1326→      },
  1327→
  1328→      // ==================== PHASE 1.4: BASELINE COMPARISON ====================
  1329→
  1330→      setBaseline: () => {
  1331→        const tasks = get().tasks;
  1332→        const baseline = createBaselineSnapshot(tasks);
  1333→        set({ baseline });
  1334→        log.info('Baseline set', { taskCount: baseline.tasks.length, setAt: baseline.setAt });
  1335→      },
  1336→
  1337→      clearBaseline: () => {
  1338→        set({ baseline: null });
  1339→        log.info('Baseline cleared');
  1340→      },
  1341→
  1342→      getBaseline: () => {
  1343→        return get().baseline || null;
  1344→      },
  1345→
  1346→      // ==================== PHASE A: ARCHIVE ACTIONS ====================
  1347→
  1348→      archiveTask: (id) => {
  1349→        const task = get().tasks.find((t) => t.id === id);
  1350→        if (!task) return;
  1351→
  1352→        const archivedTask: Task = {
  1353→          ...task,
  1354→          archivedAt: new Date().toISOString(),
  1355→        };
  1356→
  1357→        set((state) => ({
  1358→          tasks: state.tasks.filter((t) => t.id !== id),
  1359→          archivedTasks: [...(state.archivedTasks || []), archivedTask],
  1360→        }));
  1361→
  1362→        // Log archive action
  1363→        get().logActivity(id, {
  1364→          action: 'updated',
  1365→          field: 'archived',
  1366→          newValue: 'true',
  1367→        });
  1368→      },
  1369→
  1370→      restoreTask: (id) => {
  1371→        const archivedTask = get().archivedTasks?.find((t) => t.id === id);
  1372→        if (!archivedTask) return;
  1373→
  1374→        // Remove archivedAt field when restoring
  1375→        const { archivedAt, ...restoredTask } = archivedTask;
  1376→
  1377→        set((state) => ({
  1378→          archivedTasks: (state.archivedTasks || []).filter((t) => t.id !== id),
  1379→          tasks: [...state.tasks, restoredTask as Task],
  1380→        }));
  1381→
  1382→        // Log restore action
  1383→        get().logActivity(id, {
  1384→          action: 'updated',
  1385→          field: 'archived',
  1386→          oldValue: 'true',
  1387→          newValue: 'false',
  1388→        });
  1389→      },
  1390→
  1391→      deleteArchivedTask: (id) => {
  1392→        set((state) => ({
  1393→          archivedTasks: (state.archivedTasks || []).filter((t) => t.id !== id),
  1394→        }));
  1395→      },
  1396→
  1397→      getArchivedTasks: () => {
  1398→        return (get().archivedTasks || []).sort((a, b) => {
  1399→          // Sort by archive date (most recent first)
  1400→          const dateA = new Date(a.archivedAt || 0).getTime();
  1401→          const dateB = new Date(b.archivedAt || 0).getTime();
  1402→          return dateB - dateA;
  1403→        });
  1404→      },
  1405→
  1406→      autoArchiveCompletedTasks: () => {
  1407→        const now = new Date();
  1408→        const fourteenDaysAgo = new Date(now.getTime() - 14 * 24 * 60 * 60 * 1000);
  1409→
  1410→        const tasksToArchive = get().tasks.filter((task) => {
  1411→          // Only archive tasks in "done" status
  1412→          if (task.status !== 'done') return false;
  1413→
  1414→          // Check if task has been completed for > 14 days
  1415→          if (task.lastCompletedAt) {
  1416→            const completedDate = new Date(task.lastCompletedAt);
  1417→            return completedDate < fourteenDaysAgo;
  1418→          }
  1419→
  1420→          return false;
  1421→        });
  1422→
  1423→        // Archive each task
  1424→        tasksToArchive.forEach((task) => {
  1425→          get().archiveTask(task.id);
  1426→        });
  1427→
  1428→        if (tasksToArchive.length > 0) {
  1429→          log.info('Auto-archived completed tasks', { count: tasksToArchive.length });
  1430→        }
  1431→      },
  1432→
  1433→      // ==================== PHASE B: TIME TRACKING ====================
  1434→
  1435→      startTimer: (taskId) => {
  1436→        const now = new Date().toISOString();
  1437→
  1438→        set((state) => ({
  1439→          tasks: state.tasks.map((task) => {
  1440→            if (task.id === taskId) {
  1441→              return {
  1442→                ...task,
  1443→                timeTracking: {
  1444→                  estimated: task.timeTracking?.estimated,
  1445→                  actual: task.timeTracking?.actual || 0,
  1446→                  activeTimerStart: now,
  1447→                  timerHistory: task.timeTracking?.timerHistory || [],
  1448→                },
  1449→              };
  1450→            }
  1451→            return task;
  1452→          }),
  1453→        }));
  1454→
  1455→        // Log timer start
  1456→        get().logActivity(taskId, {
  1457→          action: 'updated',
  1458→          field: 'timer',
  1459→          newValue: 'started',
  1460→        });
  1461→      },
  1462→
  1463→      stopTimer: (taskId) => {
  1464→        const now = new Date().toISOString();
  1465→        const state = get();
  1466→        const task = state.tasks.find((t) => t.id === taskId);
  1467→
  1468→        if (!task || !task.timeTracking?.activeTimerStart) {
  1469→          log.warn('No active timer for task', { taskId });
  1470→          return;
  1471→        }
  1472→
  1473→        const startTime = new Date(task.timeTracking.activeTimerStart);
  1474→        const endTime = new Date(now);
  1475→        const duration = Math.floor((endTime.getTime() - startTime.getTime()) / 1000); // seconds
  1476→
  1477→        set((state) => ({
  1478→          tasks: state.tasks.map((t) => {
  1479→            if (t.id === taskId && t.timeTracking) {
  1480→              const newEntry = {
  1481→                id: crypto.randomUUID(),
  1482→                startTime: task.timeTracking!.activeTimerStart!,
  1483→                endTime: now,
  1484→                duration,
  1485→              };
  1486→
  1487→              return {
  1488→                ...t,
  1489→                timeTracking: {
  1490→                  estimated: t.timeTracking.estimated,
  1491→                  actual: t.timeTracking.actual + duration,
  1492→                  activeTimerStart: undefined,
  1493→                  timerHistory: [...(t.timeTracking.timerHistory || []), newEntry],
  1494→                },
  1495→              };
  1496→            }
  1497→            return t;
  1498→          }),
  1499→        }));
  1500→
  1501→        // Log timer stop
  1502→        get().logActivity(taskId, {
  1503→          action: 'updated',
  1504→          field: 'timer',
  1505→          oldValue: 'running',
  1506→          newValue: `stopped (+${Math.floor(duration / 60)}m)`,
  1507→        });
  1508→      },
  1509→
  1510→      updateTimeEstimate: (taskId, hours) => {
  1511→        set((state) => ({
  1512→          tasks: state.tasks.map((task) => {
  1513→            if (task.id === taskId) {
  1514→              return {
  1515→                ...task,
  1516→                timeTracking: {
  1517→                  estimated: hours,
  1518→                  actual: task.timeTracking?.actual || 0,
  1519→                  activeTimerStart: task.timeTracking?.activeTimerStart,
  1520→                  timerHistory: task.timeTracking?.timerHistory || [],
  1521→                },
  1522→              };
  1523→            }
  1524→            return task;
  1525→          }),
  1526→        }));
  1527→
  1528→        // Log estimate update
  1529→        get().logActivity(taskId, {
  1530→          action: 'updated',
  1531→          field: 'time_estimate',
  1532→          newValue: `${hours}h`,
  1533→        });
  1534→      },
  1535→
  1536→      // ==================== PHASE B: CUSTOM FIELDS ====================
  1537→
  1538→      updateEffort: (taskId, effort) => {
  1539→        set((state) => ({
  1540→          tasks: state.tasks.map((task) => {
  1541→            if (task.id === taskId) {
  1542→              const oldEffort = task.effort;
  1543→
  1544→              // Log activity if changed
  1545→              if (oldEffort !== effort) {
  1546→                setTimeout(() => {
  1547→                  get().logActivity(taskId, {
  1548→                    action: 'updated',
  1549→                    field: 'effort',
  1550→                    oldValue: oldEffort?.toString(),
  1551→                    newValue: effort?.toString(),
  1552→                  });
  1553→                }, 0);
  1554→              }
  1555→
  1556→              return { ...task, effort };
  1557→            }
  1558→            return task;
  1559→          }),
  1560→        }));
  1561→      },
  1562→
  1563→      updateCustomStatus: (taskId, customStatus) => {
  1564→        set((state) => ({
  1565→          tasks: state.tasks.map((task) => {
  1566→            if (task.id === taskId) {
  1567→              const oldStatus = task.customStatus;
  1568→
  1569→              // Log activity if changed
  1570→              if (oldStatus !== customStatus) {
  1571→                setTimeout(() => {
  1572→                  get().logActivity(taskId, {
  1573→                    action: 'updated',
  1574→                    field: 'custom_status',
  1575→                    oldValue: oldStatus,
  1576→                    newValue: customStatus,
  1577→                  });
  1578→                }, 0);
  1579→              }
  1580→
  1581→              return { ...task, customStatus };
  1582→            }
  1583→            return task;
  1584→          }),
  1585→        }));
  1586→      },
  1587→
  1588→      // ==================== BULK IMPORT ====================
  1589→
  1590→      bulkImportTasks: (importedTasks: Array<{
  1591→        title: string;
  1592→        description?: string;
  1593→        dueDate?: string;
  1594→        priority?: TaskPriority;
  1595→        tags?: string[];
  1596→        status?: TaskStatus;
  1597→        completed?: boolean;
  1598→        estimatedHours?: number;
  1599→        progress?: number;
  1600→        checklist?: Array<{ text: string; completed: boolean }>;
  1601→      }>) => {
  1602→        const now = new Date().toISOString();
  1603→        const importedTaskIds: string[] = [];
  1604→        const newTags: string[] = [];
  1605→
  1606→        // Get next card number
  1607→        let nextCardNumber = get().nextCardNumber || 1;
  1608→
  1609→        // Process tasks
  1610→        const newTasks: Task[] = importedTasks.map((imported) => {
  1611→          const taskId = crypto.randomUUID();
  1612→          importedTaskIds.push(taskId);
  1613→
  1614→          // Convert checklist to ChecklistItem format if provided
  1615→          const checklist: ChecklistItem[] | undefined = imported.checklist?.map((item, idx) => ({
  1616→            id: crypto.randomUUID(),
  1617→            text: item.text,
  1618→            completed: item.completed,
  1619→            order: idx,
  1620→            createdAt: now,
  1621→          }));
  1622→
  1623→          // Track new tags
  1624→          imported.tags?.forEach(tag => {
