  1626→              newTags.push(tag);
  1627→            }
  1628→          });
  1629→
  1630→          const task: Task = {
  1631→            id: taskId,
  1632→            title: imported.title,
  1633→            description: imported.description || '',
  1634→            status: imported.completed ? 'done' : (imported.status || 'todo'),
  1635→            created: now,
  1636→            startDate: null,
  1637→            dueDate: imported.dueDate || null,
  1638→            priority: imported.priority || 'medium',
  1639→            tags: imported.tags || [],
  1640→            cardNumber: nextCardNumber++,
  1641→            checklist,
  1642→            estimatedHours: imported.estimatedHours,
  1643→            progress: imported.progress,
  1644→            projectIds: [],
  1645→          };
  1646→
  1647→          return task;
  1648→        });
  1649→
  1650→        // Update state
  1651→        set((state) => ({
  1652→          tasks: [...state.tasks, ...newTasks],
  1653→          nextCardNumber,
  1654→        }));
  1655→
  1656→        log.info('Bulk imported tasks', {
  1657→          count: newTasks.length,
  1658→          newTags: newTags.length,
  1659→        });
  1660→
  1661→        return {
  1662→          success: true,
  1663→          tasksImported: newTasks.length,
  1664→          tagsCreated: newTags,
  1665→          errors: [],
  1666→          warnings: [],
  1667→        };
  1668→      },
  1669→
  1670→      // ==================== UI PREFERENCES ====================
  1671→
  1672→      setVisibleColumns: (count) => {
  1673→        // Validate input (3-7 columns)
  1674→        const validCount = Math.min(Math.max(count, 3), 7);
  1675→        set({ visibleColumns: validCount });
  1676→      },
  1677→
  1678→      // ==================== CARD TEMPLATES ====================
  1679→
  1680→      getCardTemplates: () => {
  1681→        return DEFAULT_CARD_TEMPLATES;
  1682→      },
  1683→    }),
  1684→    {
  1685→      name: 'kanban-tasks',
  1686→      storage: createJSONStorage(() => createSyncedStorage()),
  1687→      version: 3, // v3: Add projectIds for global project context filter
  1688→      migrate: (persistedState: any, version: number) => {
  1689→        let state = persistedState;
  1690→
  1691→        // Migration v1 -> v2: Migrate from global SimpleTaskDependency[] to task-level TaskDependency[]
  1692→        if (version < 2 && needsMigration(state)) {
  1693→          log.info('Migrating dependencies from global array to task level');
  1694→          const migratedTasks = migrateDependenciesToTaskLevel(
  1695→            state.tasks || [],
  1696→            state.dependencies || []
  1697→          );
  1698→
  1699→          state = {
  1700→            ...state,
  1701→            tasks: migratedTasks,
  1702→            dependencies: undefined, // Remove old dependencies field
  1703→          };
  1704→        }
  1705→
  1706→        // Migration v2 -> v3: Add projectIds field to all tasks
  1707→        if (version < 3 && state.tasks) {
  1708→          log.info('Adding projectIds field to all tasks');
  1709→          state = {
  1710→            ...state,
  1711→            tasks: state.tasks.map((task: any) => ({
  1712→              ...task,
  1713→              projectIds: task.projectIds ?? [],
  1714→            })),
  1715→            archivedTasks: state.archivedTasks?.map((task: any) => ({
  1716→              ...task,
  1717→              projectIds: task.projectIds ?? [],
  1718→            })),
  1719→          };
  1720→        }
  1721→
  1722→        return state;
  1723→      },
  1724→    }
  1725→  )
  1726→);
